  category?: string;
  minPrice?: number;
  maxPrice?: number;
}

export interface ProductSummary {
  count: number;
  totalInventoryValue: number;
  averagePrice: number;
}

export interface ProductListResult {
  products: Product[];
  summary: ProductSummary;
}

export interface EnrichedProduct extends Product {
  isLowStock: boolean;
  inventoryValue: number;
}

export interface OrderFilters {
  userId?: number;
  status?: string;
}

export interface OrderSummary {
  count: number;
  totalRevenue: number;
}

export interface OrderListResult {
  orders: Order[];
  summary: OrderSummary;
}

export interface EnrichedOrderItem extends OrderItem {
  productName: string;
}

export interface EnrichedOrder extends Omit<Order, 'items'> {
  items: EnrichedOrderItem[];
}
```

### 3. New File: `src/errors.ts`

A single custom error class used across both services.

```typescript
export class ServiceError extends Error {
  public readonly statusCode: number;

  constructor(statusCode: number, message: string) {
    super(message);
    this.name = "ServiceError";
    this.statusCode = statusCode;
  }
}
```

This is a standalone file rather than being embedded in `types.ts` because it is a class (runtime construct), not a type declaration. Keeping it separate follows the principle that `types.ts` contains only interfaces/types.

### 4. New File: `src/services/product-service.ts`

Create directory `src/services/` and this file. All functions are pure business logic operating on the `products` array from `../data.js`.

#### Function Signatures and Logic

```typescript
import { products } from "../data.js";
import { ServiceError } from "../errors.js";
import type {
  Product,
  ProductFilters,
  ProductListResult,
  EnrichedProduct,
} from "../types.js";

/**
 * List products with optional filters and compute summary statistics.
 * Extracted from: GET /products handler (lines 7-45 of routes/products.ts)
 */
export function listProducts(filters: ProductFilters): ProductListResult

/**
 * Get a single product by ID, enriched with isLowStock and inventoryValue.
 * Throws ServiceError(404) if not found.
 * Extracted from: GET /products/:id handler (lines 48-66)
 */
export function getProductById(id: number): EnrichedProduct

/**
 * Adjust stock for a product. Returns enriched product.
 * Throws ServiceError(404) if product not found.
 * Throws ServiceError(400) if adjustment is not a number.
 * Throws ServiceError(400) if resulting stock < 0.
 * Extracted from: PATCH /products/:id/stock handler (lines 69-97)
 */
export function adjustProductStock(id: number, adjustment: number): EnrichedProduct
```

**Detailed logic for each function:**

**`listProducts(filters)`**: Copies the products array. If `filters.category` is defined, filters by it. If `filters.minPrice` is defined and not NaN, filters `price >= minPrice`. Same for `maxPrice`. Computes `totalInventoryValue` (sum of `price * stock`, rounded to 2 decimals), `averagePrice` (mean of prices, rounded to 2 decimals, 0 if empty). Returns `{ products: filtered, summary: { count, totalInventoryValue, averagePrice } }`.

**`getProductById(id)`**: Finds product by id. If not found, throws `new ServiceError(404, "Product not found")`. Computes `isLowStock = stock < 10` and `inventoryValue = round(price * stock)`. Returns spread of product plus computed fields.

**`adjustProductStock(id, adjustment)`**: Finds product by id; throws 404 if missing. Validates `typeof adjustment !== "number"` throws `ServiceError(400, "adjustment must be a number")`. Computes `newStock = product.stock + adjustment`; if `< 0`, throws `ServiceError(400, "Insufficient stock")`. Mutates `product.stock = newStock`. Returns enriched product (same shape as `getProductById`).

Note: `adjustProductStock` receives the already-parsed `adjustment` value. The route handler is responsible for extracting it from `req.body`. However, the type validation (`typeof adjustment !== "number"`) belongs in the service because it is a business rule about the input, not HTTP parsing. This keeps the route handler maximally thin while preserving the exact same validation behavior and error messages.

### 5. New File: `src/services/order-service.ts`

#### Function Signatures and Logic

```typescript
